          title: "Quote still pending",
          body: `Your quote for ${customerName} ($${(q.total || 0).toFixed(0)}) hasn't been viewed. A quick follow-up can double your close rate.`,
          data: { screen: "QuoteDetail", quoteId: q.id },
          sound: "default"
