function generateUnsubscribeToken(userId) {
  return crypto3.createHmac("sha256", getDripSecret()).update(userId).digest("hex");
}
function verifyUnsubscribeToken(userId, token) {
  try {
    const expected = generateUnsubscribeToken(userId);
    return crypto3.timingSafeEqual(Buffer.from(expected, "hex"), Buffer.from(token, "hex"));
  } catch {
    return false;
  }
}
