// server/routes.ts
function setupSession(app2) {
  const PgStore = connectPg(session);
  const isProduction = process.env.NODE_ENV === "production" || process.env.REPLIT_DEPLOYMENT === "1";
  if (isProduction) {
    app2.set("trust proxy", 1);
  }
  app2.use(
    session({
      store: new PgStore({
        pool,
        createTableIfMissing: true
      }),
      secret: process.env.SESSION_SECRET || "quotepro-dev-secret",
      resave: false,
      saveUninitialized: false,
      cookie: {
        secure: isProduction,
        httpOnly: true,
        maxAge: 30 * 24 * 60 * 60 * 1e3,
        sameSite: "lax"
      }
    })
  );
}
async function registerRoutes(app2) {
  await initStripeClient();
  setupSession(app2);
  app2.use(adminRouter_default);
  app2.use(authRouter_default);
  app2.use(quotesRouter_default);
  app2.use(customersRouter_default);
  app2.use(jobsRouter_default);
  app2.use(pricingRouter_default);
  app2.use(aiRouter_default);
  app2.use(automationsRouter_default);
  app2.use(integrationsRouter_default);
  app2.use(businessRouter_default);
  app2.use(revenuecatRouter_default);
  app2.use(npsRouter_default);
  app2.use(quoteDoctorRouter);
  app2.use(supportRouter);
  app2.use(publicRouter_default);
  app2.use(portalRouter_default);
  const httpServer = createServer(app2);
  setInterval(async () => {
    try {
      await expireOldQuotes();
      const { sent, canceled } = await processPendingFollowUps();
      if (sent > 0 || canceled > 0) {
        console.log(`Follow-ups processed: ${sent} sent, ${canceled} canceled`);
      }
      await sendStaleQuoteNudges();
      await sendWeeklyDigestEmails();
      if (app2.__leadFinderWorker) {
        await app2.__leadFinderWorker();
      }
    } catch (e) {
      console.error("Background worker error:", e);
    }
  }, 60 * 60 * 1e3);
  return httpServer;
}

